const today = new Date();
const year = today.getFullYear();

const deadlines = {
  'Domestic Business Corporation': `${year}-06-30`,
  'Foreign Business Corporation': `${year}-06-30`,
  'Domestic Nonprofit Corporation': `${year}-06-30`,
  'Foreign Nonprofit Corporation': `${year}-06-30`,
  'Domestic LLC': `${year}-09-30`,
  'Foreign LLC': `${year}-09-30`,
  'Domestic LP': `${year}-12-31`,
  'Foreign LP': `${year}-12-31`,
  'Domestic LLP': `${year}-12-31`,
  'Business Trust': `${year}-12-31`,
  'Professional Association': `${year}-12-31`,
};

const records = $input.first().json.data?.records || [];
const results = [];

for (const record of records) {
  const fields = record.fields || {};
  const entityType = fields['Entity Type'] || 'Domestic LLC';
  const email = fields['Email'] || '';
  const name = fields['Name'] || '';
  const entityName = fields['Entity Name'] || '';

  if (!email) continue;

  const deadlineStr = deadlines[entityType] || `${year}-12-31`;
  const deadline = new Date(deadlineStr + 'T23:59:59');
  const daysUntil = Math.ceil((deadline - today) / (1000 * 60 * 60 * 24));

  if ([90, 60, 30, 14, 7].includes(daysUntil)) {
    results.push({
      json: {
        email,
        name,
        entityName,
        entityType,
        daysUntil,
        deadlineDate: deadlineStr,
        reminderType: `ar-${daysUntil}-day`,
        urgency: daysUntil <= 14 ? 'urgent' : daysUntil <= 30 ? 'warning' : 'info'
      }
    });
  }
}

if (results.length === 0) {
  results.push({ json: { noReminders: true } });
}

return results;

const d = $input.first().json;
const daysUntil = d.daysUntil;
const name = d.name || 'there';
const entity = d.entityName || 'your entity';
const deadline = d.deadlineDate;

let subject, body;

if (daysUntil === 90) {
  subject = `Reminder: ${entity} annual report due in 90 days`;
  body = `<p>Hi ${name},</p><p>This is a friendly reminder that the Pennsylvania annual report for <strong>${entity}</strong> is due on <strong>${deadline}</strong> — 90 days from now.</p><p>No action is needed yet, but we wanted to make sure it's on your radar.</p>`;
} else if (daysUntil === 60) {
  subject = `60 days until ${entity} annual report deadline`;
  body = `<p>Hi ${name},</p><p>Your PA annual report for <strong>${entity}</strong> is due on <strong>${deadline}</strong> — 60 days from now.</p><p>If you're on our Professional or Premium plan, we can file this for you. Just reply to this email with "file it" and we'll handle everything.</p>`;
} else if (daysUntil === 30) {
  subject = `⚠️ ${entity} annual report due in 30 days`;
  body = `<p>Hi ${name},</p><p>Important: Your PA annual report for <strong>${entity}</strong> is due on <strong>${deadline}</strong> — just 30 days away.</p><p>Filing takes about 5 minutes online at file.dos.pa.gov. The fee is $7 for for-profit entities. If you'd like us to handle it, reply to this email.</p>`;
} else if (daysUntil === 14) {
  subject = `🔴 URGENT: ${entity} annual report due in 14 days`;
  body = `<p>Hi ${name},</p><p><strong>Your PA annual report for ${entity} is due on ${deadline} — just 14 days away.</strong></p><p>Starting in 2027, entities that miss this deadline face administrative dissolution. Please file as soon as possible at file.dos.pa.gov.</p><p>Need help? Reply to this email or call us.</p>`;
} else if (daysUntil === 7) {
  subject = `🚨 FINAL WARNING: ${entity} annual report due in 7 DAYS`;
  body = `<p>Hi ${name},</p><p><strong>This is your final reminder.</strong> The annual report for <strong>${entity}</strong> is due on <strong>${deadline}</strong> — one week from today.</p><p>Please file immediately at <a href="https://file.dos.pa.gov">file.dos.pa.gov</a>. If you need emergency filing assistance, reply now or call us.</p>`;
}

body += `<p style="margin-top:24px;color:#6B7280;font-size:13px">— PA CROP Services<br>hello@pacropservices.com</p>`;

return [{ json: { ...d, emailSubject: subject, emailBody: body } }];
